4	import type { ClaudeAdapter, ClaudeJsonResponse } from "./claude.js";
5	import { ERROR_CODES } from "./constants.js";
6	import type { ClusterFactsheetRecord, ClusterFileHashRecord, ClusterRecord, RouterDatabase } from "./db.js";
7	import { errorPayload, type ErrorPayload, SPEC_ERROR_MESSAGES } from "./errors.js";
8	import { pickProfile, profilePromptOptions, type ClaudeToolProfile, type ProfileAvailability, type ProfileSelection } from "./profiles.js";
9	
10	export interface ClusterConsultInput {
11	  projectId: string;
12	  clusterId: string;
13	  question: string;
14	  toolProfile?: ClaudeToolProfile | null;
15	}
16	
17	export interface ClusterConsultSuccess {
18	  cluster_id: string;
19	  factsheet_id: string;
20	  factsheet_version: number;
21	  factsheet_status: string;
22	  tool_profile: ClaudeToolProfile;
23	  profile_selection: ProfileSelection;
24	  used_fork: false;
25	  claude_session_id: string;
26	  answer: string;
27	  metrics: {
28	    duration_ms: number;
29	    tokens_in?: number;
30	    tokens_out?: number;
31	  };
32	}
33	
34	export type ClusterConsultResult = ClusterConsultSuccess | ErrorPayload;
35	
36	interface LoadedClusterContext {
37	  cluster: ClusterRecord;
38	  factsheet: ClusterFactsheetRecord;
39	  fileHashes: ClusterFileHashRecord[];
40	  factsheetContent: Record<string, unknown>;
41	}
42	
43	export async function consultCluster(
44	  db: RouterDatabase,
45	  cwd: string,
46	  claude: ClaudeAdapter,
47	  availability: ProfileAvailability,
48	  input: ClusterConsultInput
49	): Promise<ClusterConsultResult> {
50	  const loaded = loadClusterContext(db, input.projectId, input.clusterId);
51	  if ("error" in loaded) {
52	    return loaded;
53	  }
54	
55	  if (loaded.factsheet.status !== "llm_verified" && loaded.cluster.static_factsheet_policy !== "allow") {
56	    return errorPayload(ERROR_CODES.CLUSTER_FACTSHEET_UNTRUSTED, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_FACTSHEET_UNTRUSTED], {
57	      cluster_id: input.clusterId,
58	      reason: `Current factsheet status is ${loaded.factsheet.status}; cluster static_factsheet_policy is ${loaded.cluster.static_factsheet_policy}.`
59	    });
60	  }
61	
62	  const staleFiles = findStaleFiles(cwd, loaded.fileHashes);
63	  if (staleFiles.length > 0) {
64	    db.markClusterFactsheetStale(loaded.factsheet.id);
65	    db.logClusterEvent({
66	      clusterId: input.clusterId,
67	      projectId: input.projectId,
68	      eventType: "cluster_refresh_required",
69	      details: {
70	        factsheet_id: loaded.factsheet.id,
71	        factsheet_version: loaded.factsheet.version,
72	        changed_files: staleFiles
73	      }
74	    });
75	    return errorPayload(ERROR_CODES.CLUSTER_FACTSHEET_STALE, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_FACTSHEET_STALE], {
76	      cluster_id: input.clusterId,
77	      details: { changed_files: staleFiles }
78	    });
79	  }
80	
81	  let profileSelection: ProfileSelection;
82	  try {
83	    profileSelection = pickProfile(input.toolProfile ?? loaded.cluster.tool_profile_default, availability);
84	  } catch (error: unknown) {
85	    return errorPayload(ERROR_CODES.CLAUDE_INVOCATION_FAILED, SPEC_ERROR_MESSAGES[ERROR_CODES.CLAUDE_INVOCATION_FAILED], {
86	      cluster_id: input.clusterId,
87	      reason: error instanceof Error ? error.message : String(error)
88	    });
89	  }
90	
91	  const start = Date.now();
92	  try {
93	    const response = claude.runPromptWithOptions
94	      ? await claude.runPromptWithOptions(buildClusterQuestionPrompt(input.question), {
95	          ...profilePromptOptions(profileSelection.selected),
96	          appendSystemPrompt: buildClusterSystemPrompt(loaded)
97	        })
98	      : await claude.runPrompt(buildClusterFallbackPrompt(loaded, input.question));
99	    const durationMs = Date.now() - start;
100	    const result: ClusterConsultSuccess = {
101	      cluster_id: input.clusterId,
102	      factsheet_id: loaded.factsheet.id,
103	      factsheet_version: loaded.factsheet.version,
104	      factsheet_status: loaded.factsheet.status,
105	      tool_profile: profileSelection.selected,
106	      profile_selection: profileSelection,
107	      used_fork: false,
108	      claude_session_id: response.sessionId,
109	      answer: response.result,
110	      metrics: {
111	        duration_ms: durationMs,
112	        tokens_in: response.tokensIn,
113	        tokens_out: response.tokensOut
114	      }
115	    };
116	    db.logClusterEvent({
117	      clusterId: input.clusterId,
118	      projectId: input.projectId,
119	      eventType: "cluster_consult",
120	      details: {
121	        factsheet_id: loaded.factsheet.id,
122	        factsheet_version: loaded.factsheet.version,
123	        factsheet_status: loaded.factsheet.status,
124	        tool_profile: profileSelection.selected,
125	        requested_profile: profileSelection.requested,
126	        downgraded: profileSelection.downgraded,
127	        used_fork: false
128	      },
129	      durationMs,
130	      tokensIn: response.tokensIn,
131	      tokensOut: response.tokensOut
132	    });
133	    if (profileSelection.downgraded) {
134	      db.logClusterEvent({
135	        clusterId: input.clusterId,
136	        projectId: input.projectId,
137	        eventType: "tool_profile_downgraded",
138	        details: profileSelection
139	      });
140	    }
